namespace sv_68b9a052962647f795a64694490dcbd1.Services;

public enum Theme
{
    Light,
    Dark,
    System
}

public sealed record ThemeState(Theme Theme, string AccentColor)
{
    public static ThemeState Default => new(Theme.System, "#0d6efd");
}

using Microsoft.JSInterop;

namespace sv_68b9a052962647f795a64694490dcbd1.Services;

/// <summary>
/// Scoped service that manages theme state for a single circuit.
/// Uses JS interop to persist state in localStorage and a BroadcastChannel
/// to synchronise across circuits (layout island ↔ page island).
/// </summary>
public sealed class ThemeService : IAsyncDisposable
{
    private readonly IJSRuntime _js;
    private IJSObjectReference? _module;
    private DotNetObjectReference<ThemeService>? _dotNetRef;

    public ThemeState Current { get; private set; } = ThemeState.Default;

    public event Action? OnChange;

    public ThemeService(IJSRuntime js) => _js = js;

    /// <summary>
    /// Call once from each interactive component's OnAfterRenderAsync(firstRender).
    /// Safe to call multiple times — only the first call initialises the JS module.
    /// </summary>
    public async Task InitAsync()
    {
        if (_module is not null) return;

        _dotNetRef = DotNetObjectReference.Create(this);
        _module = await _js.InvokeAsync<IJSObjectReference>(
            "import", "./js/theme-interop.js");

        var stored = await _module.InvokeAsync<ThemeStateDto?>("initialize", _dotNetRef);
        if (stored is not null)
        {
            Current = new ThemeState(
                Enum.Parse<Theme>(stored.Theme, ignoreCase: true),
                stored.AccentColor);
        }
    }

    public async Task SetThemeAsync(Theme theme)
    {
        Current = Current with { Theme = theme };
        await PushToJs();
        OnChange?.Invoke();
    }

    public async Task SetAccentColorAsync(string color)
    {
        Current = Current with { AccentColor = color };
        await PushToJs();
        OnChange?.Invoke();
    }

    public async Task SetAsync(Theme theme, string accentColor)
    {
        Current = new ThemeState(theme, accentColor);
        await PushToJs();
        OnChange?.Invoke();
    }

    /// <summary>
    /// Called from JS when another circuit broadcasts a change.
    /// </summary>
    [JSInvokable]
    public void OnExternalChange(ThemeStateDto dto)
    {
        Current = new ThemeState(
            Enum.Parse<Theme>(dto.Theme, ignoreCase: true),
            dto.AccentColor);
        OnChange?.Invoke();
    }

    private async Task PushToJs()
    {
        if (_module is null) return;
        await _module.InvokeVoidAsync("applyAndBroadcast",
            Current.Theme.ToString(), Current.AccentColor);
    }

    public async ValueTask DisposeAsync()
    {
        if (_module is not null)
        {
            try { await _module.InvokeVoidAsync("dispose"); } catch { }
            try { await _module.DisposeAsync(); } catch { }
        }
        _dotNetRef?.Dispose();
    }

    // DTO for JS ↔ C# serialisation
    public sealed class ThemeStateDto
    {
        public string Theme { get; set; } = "System";
        public string AccentColor { get; set; } = "#0d6efd";
    }
}

const STORAGE_KEY = "app-theme";
const CHANNEL_NAME = "app-theme-sync";

let channel;
let dotNetRef;

/** Read stored state, apply it, and start listening for cross-circuit messages. */
export function initialize(ref) {
    dotNetRef = ref;

    channel = new BroadcastChannel(CHANNEL_NAME);
    channel.onmessage = (e) => {
        applyToDom(e.data.theme, e.data.accentColor);
        dotNetRef?.invokeMethodAsync("OnExternalChange", {
            theme: e.data.theme,
            accentColor: e.data.accentColor,
        });
    };

    const raw = localStorage.getItem(STORAGE_KEY);
    if (raw) {
        try {
            const state = JSON.parse(raw);
            applyToDom(state.theme, state.accentColor);
            return state;
        } catch { /* fall through to default */ }
    }
    return null;
}

/** Persist, apply to DOM, and notify other circuits on this page. */
export function applyAndBroadcast(theme, accentColor) {
    const state = { theme, accentColor };
    localStorage.setItem(STORAGE_KEY, JSON.stringify(state));
    applyToDom(theme, accentColor);
    channel?.postMessage(state);
}

export function dispose() {
    channel?.close();
    channel = null;
    dotNetRef = null;
}

function applyToDom(theme, accentColor) {
    const resolved = resolveTheme(theme);
    document.documentElement.setAttribute("data-theme", resolved);
    document.documentElement.style.setProperty("--accent-color", accentColor);
}

function resolveTheme(theme) {
    if (theme === "System") {
        return window.matchMedia("(prefers-color-scheme: dark)").matches
            ? "Dark" : "Light";
    }
    return theme;
}

