const STORAGE_KEY = "app-theme";
const CHANNEL_NAME = "app-theme-sync";

let channel;
let dotNetRef;

/** Read stored state, apply it, and start listening for cross-circuit messages. */
export function initialize(ref) {
    dotNetRef = ref;

    channel = new BroadcastChannel(CHANNEL_NAME);
    channel.onmessage = (e) => {
        applyToDom(e.data.theme, e.data.accentColor);
        dotNetRef?.invokeMethodAsync("OnExternalChange", {
            theme: e.data.theme,
            accentColor: e.data.accentColor,
        });
    };

    const raw = localStorage.getItem(STORAGE_KEY);
    if (raw) {
        try {
            const state = JSON.parse(raw);
            applyToDom(state.theme, state.accentColor);
            return state;
        } catch { /* fall through to default */ }
    }
    return null;
}

/** Persist, apply to DOM, and notify other circuits on this page. */
export function applyAndBroadcast(theme, accentColor) {
    const state = { theme, accentColor };
    localStorage.setItem(STORAGE_KEY, JSON.stringify(state));
    applyToDom(theme, accentColor);
    channel?.postMessage(state);
}

export function dispose() {
    channel?.close();
    channel = null;
    dotNetRef = null;
}

function applyToDom(theme, accentColor) {
    const resolved = resolveTheme(theme);
    document.documentElement.setAttribute("data-theme", resolved);
    document.documentElement.style.setProperty("--accent-color", accentColor);
}

function resolveTheme(theme) {
    if (theme === "System") {
        return window.matchMedia("(prefers-color-scheme: dark)").matches
            ? "Dark" : "Light";
    }
    return theme;
}

@* Interactive island placed in the static MainLayout.
   Provides the theme indicator in the header and initialises
   the JS ↔ C# bridge for this circuit. *@
@rendermode InteractiveServer
@implements IAsyncDisposable
@inject ThemeService ThemeService

<span class="theme-indicator" style="color: var(--accent-color, @ThemeService.Current.AccentColor);">
    @GetIcon() @ThemeService.Current.Theme
</span>

@code {
    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            await ThemeService.InitAsync();
            ThemeService.OnChange += HandleChange;
            StateHasChanged();
        }
    }

    private void HandleChange() => InvokeAsync(StateHasChanged);

    private string GetIcon() => ThemeService.Current.Theme switch
    {
        Theme.Light  => "☀️",
        Theme.Dark   => "🌙",
        _            => "💻"
    };

    public async ValueTask DisposeAsync()
    {
        ThemeService.OnChange -= HandleChange;
        await ThemeService.DisposeAsync();
    }
}

