@page "/settings"
@rendermode InteractiveServer
@implements IAsyncDisposable
@inject ThemeService ThemeService
@using sv_68b9a052962647f795a64694490dcbd1.Services

<PageTitle>Settings</PageTitle>

<h1>User Preferences</h1>

<div class="card p-4" style="max-width: 480px;">
    <h5>Theme</h5>
    <div class="btn-group mb-3" role="group">
        @foreach (var t in Enum.GetValues<Theme>())
        {
            <button class="btn @(t == ThemeService.Current.Theme ? "btn-primary" : "btn-outline-secondary")"
                    @onclick="() => SetTheme(t)">
                @t
            </button>
        }
    </div>

    <h5>Accent Color</h5>
    <input type="color"
           class="form-control form-control-color mb-3"
           value="@ThemeService.Current.AccentColor"
           @onchange="SetAccentColor" />

    <p class="text-muted mb-0">
        Current: <strong>@ThemeService.Current.Theme</strong> /
        <span style="color: @ThemeService.Current.AccentColor;">@ThemeService.Current.AccentColor</span>
    </p>
</div>

@code {
    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            await ThemeService.InitAsync();
            ThemeService.OnChange += HandleChange;
            StateHasChanged();
        }
    }

    private async Task SetTheme(Theme theme) =>
        await ThemeService.SetThemeAsync(theme);

    private async Task SetAccentColor(ChangeEventArgs e) =>
        await ThemeService.SetAccentColorAsync(e.Value?.ToString() ?? "#0d6efd");

    private void HandleChange() => InvokeAsync(StateHasChanged);

    public async ValueTask DisposeAsync()
    {
        ThemeService.OnChange -= HandleChange;
        await ThemeService.DisposeAsync();
    }
}

